35→static int replaying_active = 0;
36→
37→static ox_replay_header replay_header;
38→static uint32_t frames_replayed = 0;
39→
40→/* Initial state snapshot buffer (dynamically allocated based on snapshot_size) */
41→static uint8_t *initial_snapshot = NULL;
42→static uint32_t initial_snapshot_size = 0;
43→
44→/* Read buffer for frame records */
45→#define REPLAY_BUFFER_SIZE 1024
46→static ox_frame_record replay_buffer[REPLAY_BUFFER_SIZE];
47→static int buffer_pos = 0;
48→static int buffer_count = 0;
49→
50→static int refill_buffer(void)
51→{
52→	if (!replay_file)
53→		return 0;
54→
55→	uint32_t remaining = replay_header.num_frames - frames_replayed;
56→	uint32_t to_read = remaining < REPLAY_BUFFER_SIZE ? remaining : REPLAY_BUFFER_SIZE;
57→	if (to_read == 0)
58→		return 0;
59→
60→	buffer_count = (int)fread(replay_buffer, sizeof(ox_frame_record), to_read, replay_file);
61→	buffer_pos = 0;
62→	return buffer_count;
63→}
