65→int ox_replayer_init(const char *replay_filename, const char *state_log_filename)
66→{
67→	replay_file = fopen(replay_filename, "rb");
68→	if (!replay_file) {
69→		fprintf(stderr, "OX_REPLAY: failed to open '%s' for replay\n", replay_filename);
70→		return -1;
71→	}
72→
73→	/* Read and validate header */
74→	if (fread(&replay_header, sizeof(replay_header), 1, replay_file) != 1) {
75→		fprintf(stderr, "OX_REPLAY: failed to read header from '%s'\n", replay_filename);
76→		fclose(replay_file);
77→		replay_file = NULL;
78→		return -1;
79→	}
